import actionTypes from '../action/action.types';
import userMock from '../../constants/userMock';

export default function UsersReducer(userList = userMock, action) {
  const newUserList = userList;
  switch (action.type) {
    case actionTypes.CREATE_USERS:
      newUserList = [...userList, action.toDo];
      break;

    case actionTypes.UPDATE_TODO:
      newToDoList[action.index] = action.toDo;
      newToDoList = [
        ...newToDoList
      ];
      break;

    case actionTypes.DELETE_TODO:
      newToDoList = toDoList.filter((toDo) => toDo !== action.toDo);
      break;

    default:
      break;
  }

  return newToDoList;
}
